variables.enabledLogstashInputs:
[concat('input {
', if(parameters('secureWebGateway'), variables('proxyProcessorConf').input, ''), if(parameters('identity'), variables('authProcessorConf').input, ''), if(parameters('firewall'), variables('firewallProcessorConf').input, ''), if(parameters('zeroTrustNetworkAccess'), variables('ztnaProcessorConf').input, ''), if(parameters('secureE-MailGateway'), variables('mailProcessorConf').input, ''), if(parameters('intrusionDetectionSystem'), variables('zeekProcessorConf').input, ''), '
}
')]

